import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.unmarshalling.Unmarshal
import akka.stream.ActorMaterializer
import spray.json._

import scala.concurrent.{ExecutionContextExecutor, Future}
import scala.util.{Failure, Success}

case class UrlRequest(url: String)
case class ProxyResponse(status: Int, body: String, headers: Map[String, String])

trait JsonSupport extends DefaultJsonProtocol {
  implicit val urlRequestFormat: RootJsonFormat[UrlRequest] = jsonFormat1(UrlRequest)
  implicit val proxyResponseFormat: RootJsonFormat[ProxyResponse] = jsonFormat3(ProxyResponse)
}

object WebhookProxyService extends App with JsonSupport {
  implicit val system: ActorSystem = ActorSystem("webhook-proxy-service")
  implicit val materializer: ActorMaterializer = ActorMaterializer()
  implicit val executionContext: ExecutionContextExecutor = system.dispatcher

  val route =
    pathPrefix("proxy") {
      path("fetch") {
        post {
          entity(as[String]) { requestBody =>
            val urlRequest = requestBody.parseJson.convertTo[UrlRequest]
            val userUrl = urlRequest.url

            val responseFuture: Future[ProxyResponse] = 
              Http().singleRequest(HttpRequest(uri = userUrl)).flatMap { response =>
                Unmarshal(response.entity).to[String].map { body =>
                  val headers = response.headers.map(h => h.name() -> h.value()).toMap
                  ProxyResponse(
                    status = response.status.intValue(),
                    body = body,
                    headers = headers
                  )
                }
              }

            onComplete(responseFuture) {
              case Success(proxyResponse) =>
                complete(StatusCodes.OK, proxyResponse.toJson.prettyPrint)
              case Failure(ex) =>
                complete(StatusCodes.InternalServerError, s"Error fetching URL: ${ex.getMessage}")
            }
          }
        }
